import React, { useState } from 'react';
import './App.css';
import WelcomeScreen from './components/WelcomeScreen';
import ChatInterface from './components/ChatInterface';

function App() {
  const [currentScreen, setCurrentScreen] = useState('welcome'); // 'welcome' or 'chat'
  const [language, setLanguage] = useState('en'); // 'en' or 'hi'
  const [selectedState, setSelectedState] = useState(''); // State selection

  const handleStart = () => {
    if (!selectedState) {
      alert(language === 'en' ? 'Please select your state first' : 'कृपया पहले अपना राज्य चुनें');
      return;
    }
    setCurrentScreen('chat');
  };

  const handleBack = () => {
    setCurrentScreen('welcome');
  };

  const handleLanguageChange = (newLanguage) => {
    setLanguage(newLanguage);
  };

  const handleStateChange = (state) => {
    setSelectedState(state);
  };

  return (
    <div className="app">
      {currentScreen === 'welcome' ? (
        <WelcomeScreen 
          language={language}
          onStart={handleStart}
          onLanguageChange={handleLanguageChange}
          state={selectedState}
          onStateChange={handleStateChange}
        />
      ) : (
        <ChatInterface 
          language={language}
          onLanguageChange={handleLanguageChange}
          onBack={handleBack}
          state={selectedState}
        />
      )}
    </div>
  );
}

export default App;
